```kotlin
import io.github.oshai.kotlinlogging.KotlinLogging

private val logger = KotlinLogging.logger {}

class PaymentProcessor {
    fun processPayment(paymentId: String, amount: Long) {
        logger.info { "Processing payment" }  // plain message

        // Structured fields via MDC (propagates correlation IDs across gRPC calls)
        withLoggingContext(
            "paymentId" to paymentId,
            "amount" to amount.toString()
        ) {
            logger.info { "Payment initiated" }
            // logs: {"message":"Payment initiated","paymentId":"pay_123","amount":"5000","correlationId":"..."}
        }
    }
}
```

**Correlation ID propagation** (for gRPC interceptor):

```kotlin
import io.grpc.*
import org.slf4j.MDC
import java.util.UUID

class CorrelationIdInterceptor : ServerInterceptor {
    override fun <ReqT, RespT> interceptCall(
        call: ServerCall<ReqT, RespT>,
        headers: Metadata,
        next: ServerCallHandler<ReqT, RespT>
    ): ServerCall.Listener<ReqT> {
        val correlationId = headers.get(CORRELATION_ID_KEY) ?: UUID.randomUUID().toString()
        val ctx = Context.current().withValue(CORRELATION_ID_CTX, correlationId)
        MDC.put("correlationId", correlationId)
        return Contexts.interceptCall(ctx, call, headers, next)
    }
}
```

**logback.xml** — JSON output for EKS/CloudWatch:

```xml
<configuration>
    <appender name="STDOUT" class="ch.qos.logback.core.ConsoleAppender">
        <encoder class="net.logstash.logback.encoder.LogstashEncoder">
            <includeMdcKeyName>correlationId</includeMdcKeyName>
            <includeMdcKeyName>paymentId</includeMdcKeyName>
        </encoder>
    </appender>
    <root level="INFO">
        <appender-ref ref="STDOUT" />
    </root>
</configuration>
```

